var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>퇴각! 다들 퇴각해!</color>","JPN":"<color=#ffd34c>退却！　全員、退却しろ！</color>","ENG":"<color=#ffd34c>Fall back! Retreat!</color>","TWN":"<color=#ffd34c>撤退！全員撤退！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>2소대 전원 통신 두절! 이쪽으로 온다!</color>","JPN":"<color=#ffd34c>第2小隊、全員音信不通！　こっちに来るぞ！</color>","ENG":"<color=#ffd34c>Squad 2's comms are cut off! She's coming this way!</color>","TWN":"<color=#ffd34c>第2小隊失去聯絡！她往這邊來了！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>자, 잠깐! 그거 내려 놔! 그 망할 쇠파이프 내려…!</color>","JPN":"<color=#ffd34c>ま、待て！　それを下ろせ！　その鉄パイプ、下ろ……！</color>","ENG":"<color=#ffd34c>W-wait! Put that down! Put the damn pipe...!</color>","TWN":"<color=#ffd34c>等，等等！把那個放下！放下那該死的鐵管……！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"관리부장, 저랑 잠깐 얘기 좀 해요.","JPN":"管理部長、ちょっといいですか。","ENG":"Manager, I need to speak to you for a moment.","TWN":"管理部長，我有事情要跟你說。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"펠리세트? 여긴 어쩐 일이야?","JPN":"フェリセット？　どうしたの？","ENG":"Félicette? What are you doing here?","TWN":"費莉塞特？你怎麼會來？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"미안. 머리 좀 식히라고 했는데 말을 안 들어서.","JPN":"悪い。ちょっと頭冷やせって言ったけど、話を聞かなくて。","ENG":"Sorry. I told her to cool off, but she won't listen.","TWN":"抱歉，我叫她不要衝動，但她根本聽不進去。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"나 5분 뒤에 회의야, 펠리세트. 할 얘기라면 메일에 전부 적어 뒀는데.","JPN":"5分後には会議なの、フェリセット。話ならメールに全部書いておいたんだけど。","ENG":"I have a meeting in 5 minutes, Félicette. I told you everything you needed to know in the email I sent you.","TWN":"我五分鐘後要開會，費莉塞特。我要說的全寫在信裡了。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그 메일 때문이에요.","JPN":"そのメールのことです。","ENG":"It's regarding that email.","TWN":"就是因為那封信。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"말해 봐요. 왜 저희가 예선에 출전할 수 없다는 거죠?","JPN":"話してください。どうして私たちが予選に出戦できないんですか？","ENG":"Tell me. Why can't we play in the qualifiers?","TWN":"請問，為什麼我們不能參加預賽？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"경영진 선에서 정해진 일이야. 자세히는 못 알려 줘.","JPN":"経営陣の判断なの。詳しくは話せないわ。","ENG":"It was the board's decision. I can't tell you anything in detail.","TWN":"這件事是管理層決定的，具體的原因我不能告訴你。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그럼 대충이라도 알려 줘요.","JPN":"じゃあ、ざっと話してくれるだけでもいいです。","ENG":"Then at least give me an outline.","TWN":"那就不具體地告訴我。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"호라이즌 때문인가요? 그 애한테 져서 겁먹은 거예요?","JPN":"ホライズンのせいですか？　あの子に負けて怖くなったんですか？","ENG":"Is it because of Horizon? Are they scared because we lost to her?","TWN":"是因為地平線嗎？因為我們輸給她，所以你們因此卻步？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"맞아. 겁먹었지. 그렇다고 생각해.","JPN":"そう。怖くなった。そいうことだと思って。","ENG":"Yeah. Scared. I think.","TWN":"沒錯，管理層因此卻步，就當是這樣吧。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그래서 이대로 끝내려고요?","JPN":"で、このまま終わらせるつもりですか？","ENG":"So what, this is it?","TWN":"所以呢，就這樣結束了？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"강한 상대지만 분석하면 돼요. 다음에는 더 잘 싸울 수 있어요.","JPN":"強い相手ですけど、分析すればいいんですよ。次はもっとちゃんと戦えます。","ENG":"She's a strong opponent, but we can analyze her. And we'll fight better next time.","TWN":"雖然她很強，但只要經過分析，下次我一定可以表現得更好。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OFFICER_NPC_NULL_NULL","text":{"KOREA":"하아…. 펠리세트.","JPN":"はあ……フェリセット。","ENG":"*Sigh...* Félicette.","TWN":"哀……費莉塞特。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};